static bool isCapsOnly(StringRef Name) {
  return llvm::all_of(Name, [](const char C) {
    return std::isupper(C) || std::isdigit(C) || C == '_';
  });
}

void MacroDefined(const Token &MacroNameTok, const MacroDirective *MD) override {
  if (SM.isWrittenInBuiltinFile(MD->getLocation()) ||
      MD->getMacroInfo()->isUsedForHeaderGuard() ||
      MD->getMacroInfo()->getNumTokens() == 0)
    return;

  if (IgnoreCommandLineMacros &&
      SM.isWrittenInCommandLineFile(MD->getLocation()))
    return;

  StringRef MacroName = MacroNameTok.getIdentifierInfo()->getName();
  if (MacroName == "__GCC_HAVE_DWARF2_CFI_ASM")
    return;
  if (!CheckCapsOnly && !RegExp.match(MacroName))
    Check->warnMacro(MD, MacroName);

  if (CheckCapsOnly && !isCapsOnly(MacroName))
    Check->warnNaming(MD, MacroName);
}

void MacroUsageCheck::warnMacro(const MacroDirective *MD, StringRef MacroName) {
  const MacroInfo *Info = MD->getMacroInfo();
  StringRef Message;

  if (llvm::all_of(Info->tokens(), std::mem_fn(&Token::isLiteral)))
    Message = "macro '%0' used to declare a constant; consider using a "
              "'constexpr' constant";
  else if (Info->isVariadic())
    Message = "variadic macro '%0' used; consider using a 'constexpr' "
              "variadic template function";
  else if (Info->isFunctionLike())
    Message = "function-like macro '%0' used; consider a 'constexpr' template "
              "function";

  if (!Message.empty())
    diag(MD->getLocation(), Message) << MacroName;
}

void MacroUsageCheck::warnNaming(const MacroDirective *MD, StringRef MacroName) {
  diag(MD->getLocation(), "macro definition does not define the macro name "
                          "'%0' using all uppercase characters")
      << MacroName;
}

AST_MATCHER(ParmVarDecl, isTemplateTypeParameter) {
  ast_matchers::internal::Matcher<QualType> Inner = possiblyPackExpansionOf(
      qualType(rValueReferenceType(),
               references(templateTypeParmType(
                   hasDeclaration(templateTypeParmDecl()))),
               unless(references(qualType(isConstQualified())))));
  if (!Inner.matches(Node.getType(), Finder, Builder))
    return false;

  const auto *Function = dyn_cast<FunctionDecl>(Node.getDeclContext());
  if (!Function)
    return false;

  const FunctionTemplateDecl *FuncTemplate =
      Function->getDescribedFunctionTemplate();
  if (!FuncTemplate)
    return false;

  QualType ParamType =
      Node.getType().getNonPackExpansionType()->getPointeeType();
  const auto *TemplateType = ParamType->getAs<TemplateTypeParmType>();
  if (!TemplateType)
    return false;

  return TemplateType->getDepth() ==
         FuncTemplate->getTemplateParameters()->getDepth();
}

AST_MATCHER(CXXRecordDecl, isCopyableOrMovable) {
  MemberFunctionPairInfo Constructors = getConstructorsInfo(Node);
  MemberFunctionPairInfo Assignments = getAssignmentsInfo(Node);

  if (Node.hasSimpleCopyConstructor() ||
      (Constructors.Copy.Declared && !Constructors.Copy.Deleted))
    return true;
  if (Node.hasSimpleMoveConstructor() ||
      (Constructors.Move.Declared && !Constructors.Move.Deleted))
    return true;
  if (Node.hasSimpleCopyAssignment() ||
      (Assignments.Copy.Declared && !Assignments.Copy.Deleted))
    return true;
  if (Node.hasSimpleMoveAssignment() ||
      (Assignments.Move.Declared && !Assignments.Move.Deleted))
    return true;

  return false;
}

AST_MATCHER_P(LambdaExpr, valueCapturesVar, DeclarationMatcher, VarMatcher) {
  return std::find_if(Node.capture_begin(), Node.capture_end(),
                      [&](const LambdaCapture &Capture) {
                        return Capture.capturesVariable() &&
                               VarMatcher.matches(*Capture.getCapturedVar(),
                                                  Finder, Builder) &&
                               Capture.getCaptureKind() == LCK_ByCopy;
                      }) != Node.capture_end();
}

