BindableMatcher<clang::Stmt> charCastExpression(bool IsSigned, const Matcher<clang::QualType> &IntegerType, const std::string &CastBindName) const {
  const auto IntTypedef = qualType(hasDeclaration(typedefDecl(hasAnyName(utils::options::parseStringList(CharTypdefsToIgnoreList)))));
  auto CharTypeExpr = expr();
  if (IsSigned) {
    CharTypeExpr = expr(hasType(qualType(isAnyCharacter(), isSignedInteger(), unless(IntTypedef))));
  } else {
    CharTypeExpr = expr(hasType(qualType(isAnyCharacter(), unless(isSignedInteger()), unless(IntTypedef))));
  }
  const auto ImplicitCastExpr = implicitCastExpr(hasSourceExpression(CharTypeExpr), hasImplicitDestinationType(IntegerType)).bind(CastBindName);
  const auto CStyleCastExpr = cStyleCastExpr(has(ImplicitCastExpr));
  const auto StaticCastExpr = cxxStaticCastExpr(has(ImplicitCastExpr));
  const auto FunctionalCastExpr = cxxFunctionalCastExpr(has(ImplicitCastExpr));
  return traverse(TK_AsIs, expr(anyOf(ImplicitCastExpr, CStyleCastExpr, StaticCastExpr, FunctionalCastExpr)));
}

void registerMatchers(MatchFinder *Finder) {
  const auto IntegerType = qualType(isInteger(), unless(isAnyCharacter()), unless(booleanType())).bind("integerType");
  const auto SignedCharCastExpr = charCastExpression(true, IntegerType, "signedCastExpression");
  const auto UnSignedCharCastExpr = charCastExpression(false, IntegerType, "unsignedCastExpression");
  const auto AssignmentOperatorExpr = expr(binaryOperator(hasOperatorName("="), hasLHS(hasType(IntegerType)), hasRHS(SignedCharCastExpr)));
  Finder->addMatcher(AssignmentOperatorExpr, this);
  const auto Declaration = varDecl(isDefinition(), hasType(IntegerType), hasInitializer(SignedCharCastExpr));
  Finder->addMatcher(Declaration, this);
  if (DiagnoseSignedUnsignedCharComparisons) {
    const auto CompareOperator = expr(binaryOperator(hasAnyOperatorName("==", "!="), anyOf(allOf(hasLHS(SignedCharCastExpr), hasRHS(UnSignedCharCastExpr)), allOf(hasLHS(UnSignedCharCastExpr), hasRHS(SignedCharCastExpr))))).bind("comparison");
    Finder->addMatcher(CompareOperator, this);
  }
  const auto CArraySubscript = arraySubscriptExpr(hasIndex(SignedCharCastExpr)).bind("arraySubscript");
  Finder->addMatcher(CArraySubscript, this);
  const auto STDArraySubscript = cxxOperatorCallExpr(hasOverloadedOperatorName("[]"), hasArgument(0, hasType(cxxRecordDecl(hasName("::std::array")))), hasArgument(1, SignedCharCastExpr)).bind("arraySubscript");
  Finder->addMatcher(STDArraySubscript, this);
}

